module top_module(
    input [3:0] sw,
    output reg [3:0] obf_led
);always @ (sw) begin
    case (sw)
        4'b0000: obf_led = 4'b0001;
        4'b0001: obf_led = 4'b0010;
        4'b0010: obf_led = 4'b0011;
        4'b0011: obf_led = 4'b0100;
        4'b0100: obf_led = 4'b0101;
        4'b0101: obf_led = 4'b0110;
        4'b0110: obf_led = 4'b0111;
        4'b0111: obf_led = 4'b1000;
        4'b1000: obf_led = 4'b1001;
        4'b1001: obf_led = 4'b1010;
        4'b1010: obf_led = 4'b1011;
        4'b1011: obf_led = 4'b1100;
        4'b1100: obf_led = 4'b1101;
        4'b1101: obf_led = 4'b1110;
        4'b1110: obf_led = 4'b1111;
        4'b1111: obf_led = 4'b0000;
        default: obf_led = 4'b0000;
    endcase
end

endmodule
